const validators = {
    rawCommand: function(payload) {
        const VALID = ['goal', 'waypoints', 'cancel'];
        if (!payload || typeof payload !== 'object') throw new Error('Payload must be an object');
        if (!payload.command) throw new Error('Missing field: command');
        if (!VALID.includes(payload.command)) throw new Error('Invalid command: ' + payload.command);
        if (payload.command !== 'cancel' && !payload.payload) throw new Error('Missing field: payload');
    },
    goal: function(p) {
        if (typeof p.x !== 'number') throw new Error('goal.x must be a number');
        if (typeof p.y !== 'number') throw new Error('goal.y must be a number');
        if (!p.angle || typeof p.angle !== 'object') throw new Error('goal.angle must be an object');
        ['x', 'y', 'z'].forEach(function(k) {
            if (typeof p.angle[k] !== 'number') throw new Error('goal.angle.' + k + ' must be a number');
        });
    },
    waypoints: function(p) {
        if (!Array.isArray(p.waypoints)) throw new Error('waypoints must be an array');
        if (p.waypoints.length === 0) throw new Error('waypoints array must not be empty');
        p.waypoints.forEach(function(wp, i) {
            if (typeof wp.id !== 'number') throw new Error('waypoints[' + i + '].id must be a number');
            if (typeof wp.label !== 'string') throw new Error('waypoints[' + i + '].label must be a string');
            if (typeof wp.x !== 'number') throw new Error('waypoints[' + i + '].x must be a number');
            if (typeof wp.y !== 'number') throw new Error('waypoints[' + i + '].y must be a number');
            if (!wp.angle || typeof wp.angle !== 'object') throw new Error('waypoints[' + i + '].angle must be an object');
        });
    }
};

const transformers = {
    goal: function(p) {
        return { x: p.x, y: p.y, angle: { x: p.angle.x, y: p.angle.y, z: p.angle.z } };
    },
    waypoints: function(p) {
        return { waypoints: p.waypoints };
    },
    cancel: function() {
        return {};
    }
};

const errors = {
    wrap: function(err, source) {
        return {
            timestamp: new Date().toISOString(),
            error_type: 'VALIDATION_ERROR',
            message: err.message || String(err),
            source: source || 'node-red'
        };
    }
};

global.set('lib', { validators: validators, transformers: transformers, errors: errors });
node.status({ fill: 'green', shape: 'dot', text: 'Library loaded' });
return null;

var lib = global.get('lib');
try {
    lib.validators.rawCommand(msg.payload);
    msg.command = msg.payload.command;
    msg.cmdPayload = msg.payload.payload || {};
    return [msg, null];
} catch (e) {
    var errMsg = { payload: lib.errors.wrap(e, 'validateRaw') };
    node.error(e.message, msg);
    return [null, errMsg];
}

var lib = global.get('lib');
try {
    lib.validators.goal(msg.cmdPayload);
    msg.payload = lib.transformers.goal(msg.cmdPayload);
    msg.topic = 'amr/cmd/goal';
    msg.qos = 1;
    return [msg, null];
} catch (e) {
    var errMsg = { payload: lib.errors.wrap(e, 'transformGoal') };
    node.error(e.message, msg);
    return [null, errMsg];
}

var lib = global.get('lib');
try {
    lib.validators.waypoints(msg.cmdPayload);
    msg.payload = lib.transformers.waypoints(msg.cmdPayload);
    msg.topic = 'amr/cmd/waypoints';
    msg.qos = 1;
    return [msg, null];
} catch (e) {
    var errMsg = { payload: lib.errors.wrap(e, 'transformWaypoints') };
    node.error(e.message, msg);
    return [null, errMsg];
}

var lib = global.get('lib');
msg.payload = lib.transformers.cancel();
msg.topic = 'amr/cmd/cancel';
msg.qos = 1;
return msg;

var p = msg.payload;
if (!p || !p.position || !p.timestamp) {
    node.error('Invalid odom payload', msg);
    return null;
}
node.status({ fill: 'green', shape: 'dot', text: 'x:' + p.position.x.toFixed(2) + ' y:' + p.position.y.toFixed(2) + ' [' + p.trigger + ']' });
// TODO: INSERT INTO odom
return msg;

var p = msg.payload;
if (!p || !p.timestamp) {
    node.error('Invalid pose payload', msg);
    return null;
}
node.status({ fill: 'green', shape: 'dot', text: 'px:' + p.px.toFixed(2) + ' py:' + p.py.toFixed(2) + ' rz:' + p.rz.toFixed(2) });
// TODO: INSERT INTO pose
return msg;

var p = msg.payload;
if (!p || !p.status) {
    node.error('Invalid nav status payload', msg);
    return null;
}
var fillMap = { NAVIGATING: 'blue', SUCCEEDED: 'green', ABORTED: 'red', PREEMPTED: 'yellow', IDLE: 'grey' };
node.status({ fill: fillMap[p.status] || 'grey', shape: 'dot', text: p.status });
// TODO: INSERT INTO nav_status
return msg;

var p = msg.payload;
if (!p || typeof p.current_idx !== 'number') {
    node.error('Invalid nav progress payload', msg);
    return null;
}
node.status({ fill: 'blue', shape: 'dot', text: (p.current_idx + 1) + '/' + p.total + ' (' + p.progress_pct.toFixed(0) + '%)' });
// TODO: INSERT INTO nav_progress
return msg;

var p = msg.payload;
if (!p || typeof p.connected !== 'boolean') {
    node.error('Invalid connection payload', msg);
    return null;
}
node.status({ fill: p.connected ? 'green' : 'red', shape: 'dot', text: p.connected ? 'connected' : 'disconnected' });
// TODO: UPSERT INTO health_connection
return msg;

var p = msg.payload;
if (!p || typeof p.level_pct !== 'number') {
    node.error('Invalid battery payload', msg);
    return null;
}
var fill = p.level_pct > 50 ? 'green' : p.level_pct > 20 ? 'yellow' : 'red';
node.status({ fill: fill, shape: 'dot', text: p.level_pct.toFixed(0) + '% ' + (p.charging ? '[charging]' : '') });
// TODO: INSERT INTO health_battery
return msg;

var p = msg.payload;
if (!p || !p.error_type) {
    node.error('Invalid error payload', msg);
    return null;
}
node.status({ fill: 'red', shape: 'ring', text: p.error_type + ': ' + p.message });
node.error('[' + p.source + '] ' + p.error_type + ': ' + p.message, msg);
// TODO: INSERT INTO health_error
return msg;

var p = msg.payload;
if (!p || !p.trip_id || !p.result) {
    node.error('Invalid OEE cycle payload', msg);
    return null;
}
var fill = p.result === 'SUCCEEDED' ? 'green' : 'red';
node.status({ fill: fill, shape: 'dot', text: p.trip_id + ': ' + p.result + ' (' + p.duration_s.toFixed(1) + 's)' });
// TODO: INSERT INTO oee_cycle
return msg;
